import { useState, useEffect, useCallback } from "react";
import api from "../services/api";
import PostCard from "../components/kid/PostCard";
import StoriesBar from "../components/kid/StoriesBar";
import "./Feed.css";

export default function Feed() {
  const [posts,   setPosts]   = useState([]);
  const [loading, setLoading] = useState(true);
  const [error,   setError]   = useState(null);
  const [newPost, setNewPost] = useState("");
  const [posting, setPosting] = useState(false);
  const [page,    setPage]    = useState(1);
  const [hasMore, setHasMore] = useState(true);

  const user = (() => {
    try { return JSON.parse(localStorage.getItem("user") || "{}"); }
    catch { return {}; }
  })();

  const loadFeed = useCallback(async (pageNum = 1) => {
    try {
      setError(null);
      const res = await api.get(`/posts/feed?page=${pageNum}&limit=20`);
      // Handle { success, data: { posts: [] } } OR { success, data: [] }
      const raw = res.data?.data;
      const feedPosts = Array.isArray(raw) ? raw : (raw?.posts ?? []);
      const more = raw?.hasMore ?? (feedPosts.length === 20);

      if (pageNum === 1) {
        setPosts(feedPosts);
      } else {
        setPosts(prev => [...prev, ...feedPosts]);
      }
      setHasMore(more);
      setPage(pageNum);
    } catch (err) {
      setError(err.response?.data?.message || "Could not load feed.");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { loadFeed(1); }, [loadFeed]);

  const handlePost = async () => {
    if (!newPost.trim()) return;
    setPosting(true);
    try {
      const res = await api.post("/posts", { content: newPost });
      const raw = res.data?.data;
      const created = raw?.post ?? raw;
      if (created) setPosts(prev => [created, ...prev]);
      setNewPost("");
    } catch (err) {
      alert(err.response?.data?.message || "Could not create post.");
    } finally {
      setPosting(false);
    }
  };

  const handleDelete = async (postId) => {
    try {
      await api.delete(`/posts/${postId}`);
      setPosts(prev => prev.filter(p => p.id !== postId));
    } catch {
      alert("Could not delete post.");
    }
  };

  return (
    <div className="feed-container">
      <StoriesBar />

      {/* Compose */}
      <div className="compose-box card">
        <div className="avatar avatar-md" style={{ background: user.avatar_color || '#FFE5E5' }}>
          {user.avatar_emoji || '🦊'}
        </div>
        <div className="compose-input-wrap">
          <textarea
            value={newPost}
            onChange={e => setNewPost(e.target.value)}
            placeholder="Share something kind today! 🌟"
            rows={2}
            maxLength={1000}
          />
          <button
            className="btn btn-primary btn-sm"
            onClick={handlePost}
            disabled={posting || !newPost.trim()}
          >
            {posting ? "Posting..." : "Post 🚀"}
          </button>
        </div>
      </div>

      {loading && (
        <div className="feed-loading">
          <div className="spinner" />
          <p>Loading your feed...</p>
        </div>
      )}

      {error && !loading && (
        <div className="feed-error card">
          <p>😕 {error}</p>
          <button className="btn btn-primary btn-sm" onClick={() => loadFeed(1)}>Try again</button>
        </div>
      )}

      {!loading && !error && posts.length === 0 && (
        <div className="feed-empty card">
          <p>🌈 Nothing here yet!</p>
          <p>Add some friends or be the first to post something kind.</p>
        </div>
      )}

      {posts.map(post => (
        <PostCard
          key={post.id}
          post={post}
          currentUserId={user.id}
          onDelete={handleDelete}
        />
      ))}

      {!loading && hasMore && posts.length > 0 && (
        <button
          className="btn btn-ghost load-more"
          onClick={() => loadFeed(page + 1)}
        >
          Load more
        </button>
      )}
    </div>
  );
}
